// Validate input
const body = $input.first().json.body || $input.first().json;

if (!body.xml_ref) {
  throw new Error('Missing required field: xml_ref');
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_plus_info_received'
}));

return { xml_ref: body.xml_ref };

// Parse XML to dictionary
const xmlString = $input.first().json.xml_ref;
const xml2js = require('xml2js');

const parser = new xml2js.Parser({ explicitArray: false });
const result = await parser.parseStringPromise(xmlString);

const cmdItems = result.xjx?.cmd || [];
if (!Array.isArray(cmdItems) && cmdItems) {
  cmdItems = [cmdItems];
}

if (cmdItems.length === 0) {
  throw new Error('XML must contain a <xjx><cmd> structure.');
}

const infoDict = {};
for (const item of cmdItems) {
  if (item.$ && item.$['t']) {
    infoDict[item.$['t']] = item._ || '';
  }
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_plus_info_parsed',
  fields_count: Object.keys(infoDict).length
}));

return { info_dict: infoDict };

// Transform user data: separate dependentes and beneficios by suffix
const infoDict = $input.first().json.info_dict;

const dependentes = {};
const beneficios = {};
const globalData = {};

const pattern = /_(\d+)$/;

for (const [key, value] of Object.entries(infoDict)) {
  const match = key.match(pattern);

  if (!match) {
    globalData[key] = value;
    continue;
  }

  const number = match[1];
  const baseKey = key.substring(0, match.index);

  if (baseKey.includes('dependente')) {
    if (!dependentes[number]) dependentes[number] = {};
    dependentes[number][baseKey] = value;
  } else if (baseKey.includes('beneficio')) {
    if (!beneficios[number]) beneficios[number] = {};
    beneficios[number][baseKey] = value;
  }
}

const transformedData = {
  ...globalData,
  dependentes: Object.values(dependentes),
  beneficios: Object.values(beneficios)
};

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_plus_info_transformed',
  id_funcionario: transformedData.id_funcionario,
  dependentes_count: transformedData.dependentes.length,
  beneficios_count: transformedData.beneficios.length
}));

return { transformed_data: transformedData };

// Decode HTML entities in all string fields
const data = $input.first().json.transformed_data;

function decodeHtmlEntities(obj) {
  if (typeof obj === 'string') {
    return obj
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/&nbsp;/g, ' ');
  }
  if (typeof obj === 'object' && obj !== null) {
    const decoded = Array.isArray(obj) ? [] : {};
    for (const key in obj) {
      decoded[key] = decodeHtmlEntities(obj[key]);
    }
    return decoded;
  }
  return obj;
}

const decodedData = decodeHtmlEntities(data);

return { transformed_data: decodedData };

// Parse dates from DD/MM/YYYY to ISO datetime
const data = $input.first().json.transformed_data;

function parseDate(dateStr) {
  if (!dateStr || typeof dateStr !== 'string') return null;
  const match = dateStr.match(/(\d{2})\/(\d{2})\/(\d{4})/);
  if (!match) return null;
  const [_, day, month, year] = match;
  return new Date(`${year}-${month}-${day}`).toISOString();
}

if (data.data_admissao_funcionario) {
  data.data_admissao_funcionario = parseDate(data.data_admissao_funcionario);
}

if (data.data_nascimento_funcionario) {
  data.data_nascimento_funcionario = parseDate(data.data_nascimento_funcionario);
}

// Parse dependentes dates
if (data.dependentes) {
  data.dependentes = data.dependentes.map(dep => ({
    ...dep,
    data_nascimento_dependente: parseDate(dep.data_nascimento_dependente)
  }));
}

return { transformed_data: data };

// Parse float values from Brazilian format (1.234,56 -> 1234.56)
const data = $input.first().json.transformed_data;

function parseFloat(value) {
  if (!value) return 0.0;
  let cleaned = String(value).replace(/[^\d,.]/g, '');
  if (cleaned.includes(',') && cleaned.includes('.')) {
    cleaned = cleaned.replace(/\./g, '').replace(',', '.');
  } else if (cleaned.includes(',')) {
    cleaned = cleaned.replace(',', '.');
  }
  try {
    return parseFloat(cleaned) || 0.0;
  } catch (e) {
    return 0.0;
  }
}

if (data.salario_funcionario) {
  data.salario_funcionario = parseFloat(data.salario_funcionario);
}

if (data.beneficios) {
  data.beneficios = data.beneficios.map(ben => ({
    ...ben,
    valor_beneficio: parseFloat(ben.valor_beneficio)
  }));
}

return { transformed_data: data };

// Process dependents
const empData = $input.first().json.transformed_data;
const dependentes = empData.dependentes || [];

const crypto = require('crypto');

function generateHash(input) {
  return crypto.createHash('sha256').update(String(input)).digest('hex');
}

const dependentsRecords = dependentes
  .filter(dep => dep.nome_dependente)
  .map(dep => {
    const dependentIdString = `${empData.id_funcionario}-${dep.nome_dependente}`;
    return {
      dependents_id: generateHash(dependentIdString),
      id_funcionario: empData.id_funcionario,
      nome_funcionario: empData.nome_funcionario,
      nome_dependente: dep.nome_dependente,
      tipo_dependente: dep.tipo_dependente,
      fone_dependente: dep.fone_dependente,
      rg: dep.rg,
      cpf: dep.cpf,
      data_nascimento: dep.data_nascimento_dependente
    };
  });

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_dependents_processed',
  id_funcionario: empData.id_funcionario,
  count: dependentsRecords.length
}));

return dependentsRecords.length > 0 ? dependentsRecords : [{ _skip: true, id_funcionario: empData.id_funcionario }];

// Process benefits
const empData = $input.first().json.transformed_data;
const beneficios = empData.beneficios || [];

const crypto = require('crypto');

function generateHash(input) {
  return crypto.createHash('sha256').update(String(input)).digest('hex');
}

const benefitRecords = beneficios
  .filter(ben => ben.nome_beneficio)
  .map(ben => {
    const benefitIdString = `${empData.id_funcionario}-${ben.nome_beneficio}`;
    return {
      benefit_id: generateHash(benefitIdString),
      id_funcionario: empData.id_funcionario,
      nome_funcionario: empData.nome_funcionario,
      nome: ben.nome_beneficio,
      valor: ben.valor_beneficio || 0.0
    };
  });

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_benefits_processed',
  id_funcionario: empData.id_funcionario,
  count: benefitRecords.length
}));

return benefitRecords.length > 0 ? benefitRecords : [{ _skip: true, id_funcionario: empData.id_funcionario }];

// Build success response
const empData = $input.first().json.transformed_data;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_plus_info_completed',
  id_funcionario: empData.id_funcionario,
  nome_funcionario: empData.nome_funcionario
}));

return {
  statusCode: 201,
  body: {
    message: 'Data processed and saved successfully.',
    transformed_data: empData
  }
};
